defaultpen(linewidth(1pt)+fontsize(12pt));
draw((0,0)--(0,4)--(4,4)--(4,0)--cycle);
draw((1,0)--(1,3));
draw((0,3)--(3,3));
draw((3,4)--(3,1));
draw((1,1)--(4,1));
label("$x$",(1,2),E);
label("$y$",(2,4),N);
pair a,b;
a = (0,4.31);
b = a + (4,0);
draw(a--a+(1.8,0));
draw(a+(2.2,0)--b);
